# Generated by openai (gpt-5.4)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

pipeline {
    agent any

    options {
        timestamps()
    }

    parameters {
        string(
            name: 'BUILD_COMMAND',
            defaultValue: 'echo "No build command provided"',
            description: 'Shell command(s) to build the project'
        )
        string(
            name: 'TEST_COMMAND',
            defaultValue: 'echo "No test command provided"',
            description: 'Shell command(s) to test the project'
        )
        string(
            name: 'DEPLOY_COMMAND',
            defaultValue: 'echo "No deploy command provided"',
            description: 'Shell command(s) to deploy the project'
        )
        booleanParam(
            name: 'SKIP_BUILD',
            defaultValue: false,
            description: 'Skip build stage'
        )
        booleanParam(
            name: 'SKIP_TEST',
            defaultValue: false,
            description: 'Skip test stage'
        )
        booleanParam(
            name: 'SKIP_DEPLOY',
            defaultValue: false,
            description: 'Skip deploy stage'
        )
    }

    stages {
        stage('Checkout') {
            steps {
                checkout scm
            }
        }

        stage('Build') {
            when {
                expression { !params.SKIP_BUILD }
            }
            steps {
                echo "Executing build command: ${params.BUILD_COMMAND}"
                sh label: 'Build', script: params.BUILD_COMMAND
            }
        }

        stage('Test') {
            when {
                expression { !params.SKIP_TEST }
            }
            steps {
                echo "Executing test command: ${params.TEST_COMMAND}"
                sh label: 'Test', script: params.TEST_COMMAND
            }
        }

        stage('Deploy') {
            when {
                expression { !params.SKIP_DEPLOY }
            }
            steps {
                echo "Executing deploy command: ${params.DEPLOY_COMMAND}"
                sh label: 'Deploy', script: params.DEPLOY_COMMAND
            }
        }
    }

    post {
        always {
            echo 'Pipeline execution completed.'
        }
        success {
            echo 'Pipeline finished successfully.'
        }
        failure {
            echo 'Pipeline failed.'
        }
    }
}